import { StyleSheet, Text, View } from 'react-native';

function Test() {
    const styles = StyleSheet.create({
        test: {
          color: "red",
            fontSize: 30,
            fontWeight: "bold",
            textAlign: "center",
            backgroundColor: "yellow",
            borderRadius: 5,
            paddingTop: 30
        }
     });
    return <Text style={styles.test}>Pokedex</Text>
}

export default Test;
